import {
  cognitiveSlack,
  coolingTrigger,
  mergeAllowedWhenCooling,
} from '../cooling-policy';

if (cognitiveSlack(4, 2) !== 0.5) throw new Error('slack');
const params = { K: 4, L: 3, alertRateMax: 10 };
if (
  !coolingTrigger(params, { arousalProxy: 0, alertRatePerMin: 0, mode: 'normal' }, 0.5, 99)
) {
  throw new Error('expected trigger low slack');
}
if (coolingTrigger(params, { arousalProxy: 0, alertRatePerMin: 0, mode: 'normal' }, 0.1, 99)) {
  throw new Error('unexpected trigger');
}
if (mergeAllowedWhenCooling({ arousalProxy: 0, alertRatePerMin: 0, mode: 'cooling' })) {
  throw new Error('merge blocked in cooling');
}
